import { Component, h, Prop } from '@stencil/core';
@Component({
  tag: 'bst-button',
  styleUrl: 'bst-button.scss',
  shadow: true,
})
export class BstButton {
  /******************************************************************
   * PROPS
   ******************************************************************/

  /**
   * Text to display in the button
   */
  @Prop() text: string = '';

  /**
   * Function to call when the button is clicked
   */
  @Prop() clickHandler: (e: MouseEvent) => void;

  /**
   * Boolean to indicate if the component is loading and disabled
   */
  @Prop() isLoading: boolean = false;

  /**
   * String with the id to apply to the button
   */
  @Prop() componentId: string;

  /**
   * String with the classes to apply to the button
   */
  @Prop() classes: string = 'btn btn--primary btn--block btn--medium btn--font-xs';

  /******************************************************************
   * RENDERS
   ******************************************************************/

  render() {
    return (
      <button
        id={this.componentId}
        class={`${this.classes} ${this.isLoading ? 'btn--loading act-disabled' : ''}`}
        onClick={this.clickHandler}
        disabled={this.isLoading}>
        <span class='text'>
          {this.text}
        </span>
      </button>
    );
  }
}